args.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?competitor ?position ?competitorLabel
WHERE {
  {
    SELECT ?event
    WHERE {
      ?event wdt:P31 wd:Q816145 .
      ?event wdt:P585 ?date .
    }
    ORDER BY DESC(?date)
    LIMIT 1
  }
  ?event p:P185 ?participantStatement .
  ?participantStatement ps:P185 ?competitor .
  ?participantStatement pq:P268 ?position .
  FILTER (?position <= 3)
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en" }
}
ORDER BY ?position
LIMIT 3
